// Definição dos buffers globais
float g_static_attn_out_buffer[CONTEXT_LENGTH * EMB_DIM];
float g_static_norm_out_buffer[CONTEXT_LENGTH * EMB_DIM];
float g_static_ff_out_buffer[CONTEXT_LENGTH * EMB_DIM];
